#include <vector>

using namespace std;

bool solve(long long n) {
    long long original = n;
    int sum = 0;
    long long product = 1;

    while (n > 0) {
        int digit = n % 10;
        sum += digit;
        product *= digit;
        n /= 10;
    }

    long long total = sum + product;

    if (total == 0) {
        return false;
    }

    return (original % total) == 0;
}
